 80→async function requestRegistration(opts) {
 81→    const base = resolveApiBase(opts.apiBase);
 82→    const network = opts.network ?? "mainnet";
 83→    const payload = {
 84→        mode: opts.mode,
 85→        network,
 86→        disclosures: opts.disclosures,
 87→        humanAddress: opts.humanAddress,
 88→        agentName: opts.agentName,
 89→        agentDescription: opts.agentDescription,
 90→    };
 91→    const data = await apiFetch(`${base}/api/agent/register`, {
 92→        method: "POST",
 93→        headers: { "Content-Type": "application/json" },
 94→        body: JSON.stringify(payload),
 95→    });
 96→    return buildRegistrationSession(data, base);
 97→}
 98→/**
 99→ * Initiate agent deregistration through the Self Agent ID REST API.
100→ */
101→async function requestDeregistration(opts) {
102→    const base = resolveApiBase(opts.apiBase);
103→    const network = opts.network ?? "mainnet";
104→    const payload = {
105→        network,
106→        agentAddress: opts.agentAddress,
107→        disclosures: opts.disclosures,
108→    };
109→    const data = await apiFetch(`${base}/api/agent/deregister`, {
110→        method: "POST",
111→        headers: { "Content-Type": "application/json" },
112→        body: JSON.stringify(payload),
113→    });
114→    return buildDeregistrationSession(data, base);
115→}
116→/**
117→ * Initiate a proof refresh for an existing agent through the Self Agent ID REST API.
118→ *
119→ * Returns a session object with a deep link for the human to scan in the Self app,
120→ * and a polling method to wait for the new proof to be recorded on-chain.
121→ */
122→async function requestProofRefresh(opts) {
123→    const base = resolveApiBase(opts.apiBase);
124→    const network = opts.network ?? "mainnet";
125→    const payload = {
126→        agentId: opts.agentId,
127→        network,
128→        disclosures: opts.disclosures,
129→    };
130→    const data = await apiFetch(`${base}/api/agent/refresh`, {
131→        method: "POST",
132→        headers: { "Content-Type": "application/json" },
133→        body: JSON.stringify(payload),
134→    });
135→    return buildRefreshSession(data, base);
136→}
137→/**
138→ * Fetch agent info from the public query API.
139→ */
140→async function getAgentInfo(agentId, opts) {
141→    const base = resolveApiBase(opts?.apiBase);
