  1→"use client";
  2→
  3→import { useState } from "react";
  4→import { useAccount, useSendTransaction } from "wagmi";
  5→import { parseEther } from "viem";
  6→import { SelfVerification } from "@/components/self-verification";
  7→import { LendingDashboard } from "@/components/lending-dashboard";
  8→
  9→const STEPS = [
 10→  { id: "deploy", label: "Deploy Agent" },
 11→  { id: "verify", label: "Verify Identity" },
 12→  { id: "fund", label: "Fund Agent" },
 13→  { id: "monitor", label: "Monitor" },
 14→] as const;
 15→
 16→type Step = (typeof STEPS)[number]["id"];
 17→
 18→const labelClass =
 19→  "font-mono text-xs uppercase tracking-[0.15em] text-ink-lighter";
 20→const inputClass =
 21→  "w-full border-b border-cream-dark bg-transparent px-0 py-2 text-sm text-ink placeholder:text-ink-lighter focus:border-ink focus:outline-none";
 22→
 23→export function DeployAgent() {
 24→  const { address } = useAccount();
 25→  const { sendTransactionAsync } = useSendTransaction();
 26→  const [step, setStep] = useState<Step>("deploy");
 27→  const [isVerified, setIsVerified] = useState(false);
 28→  const [agentAddress, setAgentAddress] = useState<string | null>(null);
 29→  const [deploying, setDeploying] = useState(false);
 30→  const [agentName, setAgentName] = useState("");
 31→  const [fundAmount, setFundAmount] = useState("");
 32→  const [funding, setFunding] = useState(false);
 33→  const [funded, setFunded] = useState(false);
 34→
 35→  const handleDeploy = async () => {
 36→    if (!agentName.trim()) return;
 37→    setDeploying(true);
 38→    try {
 39→      const res = await fetch("/api/agent/deploy", {
 40→        method: "POST",
 41→        headers: { "Content-Type": "application/json" },
 42→        body: JSON.stringify({ agentName: agentName.trim() }),
 43→      });
 44→      const data = await res.json();
 45→      if (data.walletAddress) {
 46→        setAgentAddress(data.walletAddress);
 47→        setStep("verify");
 48→      }
 49→    } catch (err) {
 50→      console.error("Deploy failed:", err);
 51→    } finally {
 52→      setDeploying(false);
 53→    }
 54→  };
 55→
 56→  const handleVerificationSuccess = (agentAddr: string) => {
 57→    setIsVerified(true);
 58→    setAgentAddress(agentAddr);
 59→    setStep("fund");
 60→  };
 61→
 62→  const handleFund = async () => {
 63→    if (!agentAddress || !fundAmount) return;
 64→    const amount = parseFloat(fundAmount);
 65→    if (!amount || amount <= 0) return;
 66→
 67→    setFunding(true);
 68→    try {
 69→      await sendTransactionAsync({
 70→        to: agentAddress as `0x${string}`,
 71→        value: parseEther(fundAmount),
 72→      });
 73→      setFunded(true);
 74→      setStep("monitor");
 75→    } catch (err) {
 76→      console.error("Funding failed:", err);
 77→    } finally {
 78→      setFunding(false);
 79→    }
 80→  };
 81→
 82→  const currentIdx = STEPS.findIndex((x) => x.id === step);
 83→
 84→  if (!address) {
 85→    return (
 86→      <div className="mx-auto max-w-md text-center">
 87→        <h3 className="font-serif text-2xl text-ink">Connect your wallet.</h3>
 88→        <p className="mt-4 text-sm leading-relaxed text-ink-light">
 89→          Connect your wallet to deploy your autonomous agent and access
 90→          on-chain lending on Celo.
 91→        </p>
 92→      </div>
 93→    );
 94→  }
 95→
 96→  return (
 97→    <div className="space-y-12">
 98→      {/* Agent info bar */}
 99→      {agentAddress && (
100→        <div className="flex items-center justify-between border-b border-cream-dark pb-4">
101→          <div>
102→            <span className={labelClass}>Agent Wallet</span>
103→            <p className="mt-1 font-mono text-sm text-ink">
104→              {agentAddress.slice(0, 6)}...{agentAddress.slice(-4)}
105→            </p>
106→          </div>
107→          <div>
108→            <span className={labelClass}>Network</span>
109→            <p className="mt-1 font-mono text-sm text-ink">Celo</p>
110→          </div>
111→          <div>
112→            <span className={labelClass}>Identity</span>
113→            <p className="mt-1 font-mono text-sm text-ink">
114→              {isVerified ? "Self (8004 SBT)" : "Not verified"}
115→            </p>
116→          </div>
117→          <div>
118→            <span className={labelClass}>Status</span>
119→            <p className="mt-1 font-mono text-sm text-ink">
120→              {funded ? "Funded" : "Unfunded"}
121→            </p>
122→          </div>
123→        </div>
124→      )}
125→
126→      {/* Step indicator */}
127→      <div className="flex items-center gap-3">
128→        {STEPS.map((s, i) => {
129→          const isDone = currentIdx > i;
130→          const isCurrent = step === s.id;
131→          return (
132→            <div key={s.id} className="flex items-center gap-3">
133→              <div className="flex items-center gap-2">
134→                <span
135→                  className={`font-mono text-xs ${isCurrent ? "text-ink" : isDone ? "text-ink-light" : "text-ink-lighter"}`}
136→                >
137→                  {isDone ? "\u2713" : `0${i + 1}`}
138→                </span>
139→                <button
140→                  onClick={() => {
141→                    if (isDone || isCurrent) setStep(s.id);
142→                  }}
143→                  disabled={!isDone && !isCurrent}
144→                  className={`font-mono text-xs uppercase tracking-wider ${isCurrent ? "text-ink" : isDone ? "text-ink-light cursor-pointer hover:text-ink" : "text-ink-lighter"}`}
145→                >
146→                  {s.label}
147→                </button>
148→              </div>
149→              {i < STEPS.length - 1 && (
150→                <div className="h-px w-12 bg-cream-dark" />
151→              )}
152→            </div>
153→          );
154→        })}
155→      </div>
156→
157→      {/* Step 1: Deploy Agent */}
158→      {step === "deploy" && (
159→        <div className="mx-auto max-w-md">
160→          <h3 className="font-serif text-xl text-ink">Deploy your agent</h3>
161→          <p className="mt-2 text-sm text-ink-light">
162→            Deploy a Dockerized OpenClaw agent instance. Your connected wallet
163→            serves as the human anchor for the agent lifecycle.
