            <div>
              <label className={labelClass}>Amount</label>
              <div className="flex items-baseline gap-2">
                <input
                  type="number"
                  value={fundAmount}
                  onChange={(e) => setFundAmount(e.target.value)}
                  placeholder="0.00"
                  className={inputClass}
                />
