import { createViemAccount } from "@privy-io/node/viem";
import { to7702SimpleSmartAccount } from "permissionless/accounts";
import { createSmartAccountClient } from "permissionless";

// Config from env
const PRIVY_APP_ID = process.env.PRIVY_APP_ID!;
const PRIVY_APP_SECRET = process.env.PRIVY_APP_SECRET!;
const WALLET_ID = process.env.AGENT_WALLET_ID || "otieg10rrur0ba0bl42wzsxx";
const WALLET_ADDRESS = (process.env.AGENT_WALLET_ADDRESS || "0xb066DD809898559D6eF3Aeb0E59f9b41e81e5Cb6") as `0x${string}`;
const CANDIDE_API_KEY = process.env.CANDIDE_API_KEY || "";
const CANDIDE_URL = CANDIDE_API_KEY
  ? `https://api.candide.dev/api/v3/42220/${CANDIDE_API_KEY}`
  : "https://api.candide.dev/public/v3/42220";
const SPONSORSHIP_POLICY_ID = process.env.CANDIDE_SPONSORSHIP_POLICY_ID || "";

// Self Agent Registry EIP-712 domain (for signing test)
const REGISTRY_ADDRESS = "0x62E37d0f6c5f67784b8828B3dF68BCDbB2e55095" as const;
const EIP712_DOMAIN = {
  name: "SelfAgentRegistry",
  version: "1",
  chainId: 42220,
  verifyingContract: REGISTRY_ADDRESS,
} as const;
const AGENT_WALLET_SET_TYPES = {
  AgentWalletSet: [
    { name: "agentId", type: "uint256" },
    { name: "newWallet", type: "address" },
    { name: "owner", type: "address" },
    { name: "nonce", type: "uint256" },
    { name: "deadline", type: "uint256" },
  ],
} as const;

async function main() {
  console.log("=== EIP-7702 + Candide + Privy Test ===\n");
  console.log("Wallet ID:", WALLET_ID);
  console.log("Wallet Address:", WALLET_ADDRESS);
  console.log("Candide URL:", CANDIDE_URL.replace(CANDIDE_API_KEY, "***"));
  console.log("Sponsorship Policy:", SPONSORSHIP_POLICY_ID || "(none)");
  console.log();

  // --- Step 1: Create Privy viem account ---
  console.log("1. Creating Privy viem account...");
  const privy = new PrivyClient({ appId: PRIVY_APP_ID, appSecret: PRIVY_APP_SECRET });
  const owner = await createViemAccount(privy, {
    walletId: WALLET_ID,
    address: WALLET_ADDRESS,
  });
  console.log("   ✓ Privy account created:", owner.address);

  // --- Step 2: Create 7702 smart account ---
  console.log("\n2. Creating EIP-7702 smart account...");
  const publicClient = createPublicClient({
    chain: celo,
    transport: http("https://forno.celo.org"),
  });

  const account = await to7702SimpleSmartAccount({
    client: publicClient,
    owner,
    entryPoint: {
      address: entryPoint08Address,
      version: "0.8",
    },
  });
  console.log("   ✓ 7702 account address:", account.address);
  console.log("   ✓ Same as EOA?", account.address.toLowerCase() === WALLET_ADDRESS.toLowerCase());

  // --- Step 3: Test EIP-712 signing ---
  console.log("\n3. Testing EIP-712 signing (AgentWalletSet)...");
  const testMessage = {
    agentId: BigInt(1),
    newWallet: WALLET_ADDRESS,
    owner: "0x0000000000000000000000000000000000000001" as `0x${string}`,
    nonce: BigInt(0),
    deadline: BigInt(Math.floor(Date.now() / 1000) + 3600),
  };

  try {
    const signature = await owner.signTypedData({
      domain: EIP712_DOMAIN,
      types: AGENT_WALLET_SET_TYPES,
      primaryType: "AgentWalletSet",
      message: testMessage,
    });
    console.log("   ✓ EIP-712 signature:", signature.slice(0, 20) + "...");
    console.log("   ✓ Signature length:", signature.length, "chars");
  } catch (err: any) {
    console.log("   ✗ EIP-712 signing failed:", err.message);
  }

  // --- Step 4: Test Candide bundler connectivity ---
  console.log("\n4. Testing Candide bundler...");
  try {
    const bundlerRes = await fetch(CANDIDE_URL, {
      method: "POST",
      headers: { "Content-Type": "application/json" },
      body: JSON.stringify({
        jsonrpc: "2.0",
        method: "eth_supportedEntryPoints",
        params: [],
        id: 1,
      }),
    });
    const bundlerData = await bundlerRes.json();
    console.log("   ✓ Supported EntryPoints:", bundlerData.result);
    const hasV08 = bundlerData.result?.some((ep: string) =>
      ep.toLowerCase() === entryPoint08Address.toLowerCase()
    );
    console.log("   ✓ v0.8 supported?", hasV08);
  } catch (err: any) {
    console.log("   ✗ Bundler check failed:", err.message);
  }

  // --- Step 5: Test sponsored UserOp (self-transfer of 0 value) ---
  console.log("\n5. Testing Candide gas sponsorship (sending 0-value self-transfer)...");
  try {
    const paymasterClient = createClient({
      chain: celo,
      transport: http(CANDIDE_URL),
    });

    const smartAccountClient = createSmartAccountClient({
      account,
      chain: celo,
      bundlerTransport: http(CANDIDE_URL),
      paymaster: {
        getPaymasterData: async (userOp) => {
          const res = await paymasterClient.request({
            method: "pm_sponsorUserOperation" as any,
            params: [userOp, entryPoint08Address, { sponsorshipPolicyId: SPONSORSHIP_POLICY_ID }] as any,
          });
          return res as any;
        },
        getPaymasterStubData: async (userOp) => {
          const res = await paymasterClient.request({
            method: "pm_sponsorUserOperation" as any,
            params: [userOp, entryPoint08Address, { sponsorshipPolicyId: SPONSORSHIP_POLICY_ID }] as any,
          });
          return res as any;
        },
      },
      userOperation: {
        estimateFeesPerGas: async () => {
          const block = await publicClient.getBlock();
          const baseFee = block.baseFeePerGas ?? BigInt(5000000000);
          return {
            maxFeePerGas: baseFee * BigInt(2),
            maxPriorityFeePerGas: baseFee / BigInt(5),
          };
        },
      },
    });

    // Send a 0-value self-transfer to test the full pipeline
    const txHash = await smartAccountClient.sendTransaction({
      to: WALLET_ADDRESS,
      value: BigInt(0),
      data: "0x",
    });
    console.log("   ✓ Sponsored tx hash:", txHash);
    console.log("   ✓ View on explorer: https://celoscan.io/tx/" + txHash);
  } catch (err: any) {
    console.log("   ✗ Sponsored tx failed:", err.message);
    if (err.details) console.log("     Details:", err.details);
    if (err.cause) console.log("     Cause:", String(err.cause));
  }

  console.log("\n=== Test complete ===");
}

main().catch((err) => {
  console.error("Fatal error:", err);
  process.exit(1);
});

