 * 2. EIP-712 typed data signing (AgentWalletSet)
 * 3. Candide sponsored transaction (gas sponsorship)
 *
 * Usage: npx tsx test-7702.ts
 */

import { createPublicClient, createClient, http, encodeFunctionData } from "viem";
