    const paymasterClient = createClient({
      chain: celo,
      transport: http(CANDIDE_URL),
    });

    // Helper to convert UserOp fields to hex for Candide's RPC
    function toPackedUserOp(userOp: any) {
      const toHex = (v: any) => {
        if (typeof v === "bigint") return "0x" + v.toString(16);
        if (typeof v === "number") return "0x" + v.toString(16);
        if (typeof v === "string" && !v.startsWith("0x")) return "0x" + BigInt(v).toString(16);
        return v;
      };
      return {
        sender: userOp.sender,
        nonce: toHex(userOp.nonce),
        callData: userOp.callData,
        callGasLimit: toHex(userOp.callGasLimit ?? 0),
        verificationGasLimit: toHex(userOp.verificationGasLimit ?? 0),
        preVerificationGas: toHex(userOp.preVerificationGas ?? 0),
        maxFeePerGas: toHex(userOp.maxFeePerGas ?? 0),
        maxPriorityFeePerGas: toHex(userOp.maxPriorityFeePerGas ?? 0),
        signature: userOp.signature ?? "0x",
        ...(userOp.factory ? { factory: userOp.factory } : {}),
        ...(userOp.factoryData ? { factoryData: userOp.factoryData } : {}),
        ...(userOp.paymaster ? { paymaster: userOp.paymaster } : {}),
        ...(userOp.paymasterData ? { paymasterData: userOp.paymasterData } : {}),
        ...(userOp.paymasterVerificationGasLimit ? { paymasterVerificationGasLimit: toHex(userOp.paymasterVerificationGasLimit) } : {}),
        ...(userOp.paymasterPostOpGasLimit ? { paymasterPostOpGasLimit: toHex(userOp.paymasterPostOpGasLimit) } : {}),
        ...((() => {
          const auth = userOp.eip7702Auth?.[0] || userOp.authorization;
          if (!auth) return {};
          return {
            eip7702Auth: {
              chainId: toHex(auth.chainId),
              address: auth.address,
              nonce: toHex(auth.nonce ?? 0),
              r: auth.r,
              s: auth.s,
              yParity: toHex(auth.yParity ?? 0),
            },
          };
        })()),
      };
    }

    async function sponsorUserOp(userOp: any) {
      const packed = toPackedUserOp(userOp);
      console.log("   [debug] packed keys:", Object.keys(packed));
      console.log("   [debug] has eip7702Auth?", "eip7702Auth" in packed);
      console.log("   [debug] has authorization?", "authorization" in userOp);
      console.log("   [debug] authorization:", JSON.stringify(userOp.authorization, (_, v) => typeof v === "bigint" ? v.toString() : v));
      console.log("   [debug] packed eip7702Auth:", JSON.stringify(packed.eip7702Auth));
      const res = await fetch(CANDIDE_URL, {
        method: "POST",
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify({
          jsonrpc: "2.0",
          method: "pm_sponsorUserOperation",
          params: [packed, entryPoint08Address, { sponsorshipPolicyId: SPONSORSHIP_POLICY_ID }],
          id: Date.now(),
        }),
      });
      const data = await res.json();
      if (data.error) throw new Error(data.error.message || JSON.stringify(data.error));
      return data.result;
    }

    const smartAccountClient = createSmartAccountClient({
      account,
      chain: celo,
      bundlerTransport: http(CANDIDE_URL),
      paymaster: {
        getPaymasterData: async (userOp) => sponsorUserOp(userOp),
        getPaymasterStubData: async (userOp) => sponsorUserOp(userOp),
      },
      userOperation: {
        estimateFeesPerGas: async () => {
          const block = await publicClient.getBlock();
          const baseFee = block.baseFeePerGas ?? BigInt(5000000000);
          return {
            maxFeePerGas: baseFee * BigInt(2),
            maxPriorityFeePerGas: baseFee / BigInt(5),
          };
        },
      },
    });

    // Send a 0-value self-transfer to test the full pipeline
    const txHash = await smartAccountClient.sendTransaction({
      to: WALLET_ADDRESS,
      value: BigInt(0),
      data: "0x",
    });
    console.log("   ✓ Sponsored tx hash:", txHash);
    console.log("   ✓ View on explorer: https://celoscan.io/tx/" + txHash);
  } catch (err: any) {
    console.log("   ✗ Sponsored tx failed:", err.message);
    if (err.details) console.log("     Details:", err.details);
    if (err.cause) console.log("     Cause:", String(err.cause));
  }

  console.log("\n=== Test complete ===");
}

main().catch((err) => {
  console.error("Fatal error:", err);
  process.exit(1);
});

