  const userOpHash = await publicClient.readContract({
    address: entryPoint08Address,
    abi: [{
      name: "getUserOpHash",
      type: "function",
      stateMutability: "view",
      inputs: [{
        name: "userOp",
        type: "tuple",
        components: [
          { name: "sender", type: "address" },
          { name: "nonce", type: "uint256" },
          { name: "initCode", type: "bytes" },
